 */

const { amostras } = $("Gatilho").first().json;

const janelas = $("Aleatoriza a ordem")
  .all()
  .map(({ json }) => json)
  // Se `amostras` não foi informado, retorna todas as janelas
  .slice(0, amostras ?? undefined);

return janelas.sort(
  (a, b) =>
    new Date(a.inicio_janela).getTime() -
    new Date(b.inicio_janela).getTime()
);"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[4240,1360],"id":"5cb29c7b-2345-43e4-9c63-b8b585852ba3","name":"Selecionar amostras","alwaysOutputData":false},{"parameters":{"jsCode":"/**
 * Verificar se as janelas de tempo disponíveis não conflitam com eventos já agendados.
 */
const janelas = $("Selecionar amostras")
  .all()
  .map(({ json }) => ({
    inicio_janela: DateTime.fromJSDate(new Date(json.inicio_janela)),
    fim_janela: DateTime.fromJSDate(new Date(json.fim_janela)),
  }));

const eventos = $("Consulta eventos no período").all();
const id_agenda = $("Configurações").first().json.id_agenda;

// Se não há eventos agendados, todas as janelas estão disponíveis
if (Object.keys(eventos[0].json).length === 0) {
  return janelas.map(({ inicio_janela, fim_janela }) => ({
    inicio_janela,
    fim_janela,
    id_agenda,
  }));
}

const periodo_eventos = eventos.map(({ json }) => ({
  inicio_evento: DateTime.fromJSDate(new Date(json.start.dateTime)),
  fim_evento: DateTime.fromJSDate(new Date(json.end.dateTime)),
}));

return janelas
  .filter(({ inicio_janela, fim_janela }) => {
    for (const { inicio_evento, fim_evento } of periodo_eventos) {
      if (inicio_janela < fim_evento && fim_janela > inicio_evento) {
        // Overlap da janela com o evento
        return false;
      }
    }
    return true;
  })
  .map(({ inicio_janela, fim_janela }) => ({
    inicio_janela,
    fim_janela,
    id_agenda,
  }));
"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[4464,1360],"id":"6cc778a7-e3ce-4ee7-bd38-811a176768a4","name":"Verificar eventos na agenda","alwaysOutputData":true},{"parameters":{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":2},"conditions":[{"id":"9e63d847-edcd-4d79-9526-b9d42f1358c7","leftValue":"={{ '{'+'{' }} [10, 15, 20, 30, 45, 60, 90, 120] {{ '}'+'}' }}","rightValue":"={{ '{'+'{' }} $json.tamanho_janela_minutos || 60 {{ '}'+'}' }}","operator":{"type":"array","operation":"contains","rightType":"any"}},{"id":"e06a278f-6b16-4f1e-8e04-78002eb7f02d","leftValue":"={{ '{'+'{' }} [10, 15, 20, 30, 45, 60, 90, 120] {{ '}'+'}' }}","rightValue":"={{ '{'+'{' }} $json.granularidade || 30 {{ '}'+'}' }}","operator":{"type":"array","operation":"contains","rightType":"any"}}],"combinator":"and"},"options":{}},"type":"n8n-nodes-base.if","typeVersion":2.2,"position":[1776,1360],"id":"0d1b12f6-5210-4ff5-be5b-47f3f41d3037","name":"Tamanho janela válido?"},{"parameters":{"operation":"getAll","calendar":{"__rl":true,"value":"={{ '{'+'{' }} $('Configurações').item.json.id_agenda {{ '}'+'}' }}","mode":"id"},"returnAll":true,"timeMin":"={{ '{'+'{' }} $('Configurações').item.json.periodo_inicio_timestamp.toDateTime('s') {{ '}'+'}' }}","timeMax":"={{ '{'+'{' }} $('Configurações').item.json.periodo_fim_timestamp.toDateTime('s') {{ '}'+'}' }}","options":{"recurringEventHandling":"expand","showHiddenInvitations":true}},"type":"n8n-nodes-base.googleCalendar","typeVersion":1.3,"position":[2912,1360],"id":"3b056851-1052-4494-aeeb-065a23e088e7","name":"Consulta eventos no período","alwaysOutputData":true,"credentials":{}},{"parameters":{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":2},"conditions":[{"id":"ed84157f-b3d7-454c-88e9-099a28153c0a","leftValue":"={{ '{'+'{' }} $('Gatilho').item.json.periodo_inicio.toDateTime() {{ '}'+'}' }}","rightValue":"= {{ '{'+'{' }} $now {{ '}'+'}' }